var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"무사히 목적지에 도착했다, 제군들!","JPN":"皆、着いたよ！","ENG":"We've safely arrived at the destination!","TWN":"我們安全到達目的地了，各位！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"여기가 모험의 종착지인 블루로즈 섬이야!","JPN":"ここが冒険の最終地点、ブルーローズ島だ！","ENG":"This is the last stop of the journey, Blue Rose Island!","TWN":"這裡就是冒險的終點，藍玫瑰島！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"전원 한 줄로 서서 질서 있게 입장하도록!","JPN":"全員ちゃんと一列に並んでね！","ENG":"Everyone, make a line and enter in an orderly manner!","TWN":"全員排成一列，依序入場！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"확인했습니다. 그럼 즐거운 시간 되세요!","JPN":"確認いたしました。それでは素敵な時間を！","ENG":"Confirmed. Have a great time!","TWN":"好的，已確認。祝你們玩得開心！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"휴우.","JPN":"ふう。","ENG":"Phew.","TWN":"呼。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마 섬에 들어오는 데에도 입장권이 필요한 줄은 몰랐네요.","JPN":"まさか島への上陸にチケットが必要だとは思いませんでした。","ENG":"I didn't think we'd need tickets to enter the island.","TWN":"沒想到進島也需要入場券。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"기껏 여기까지 왔는데 문전박대 당했으면… 으으.","JPN":"ここまで来て、上陸もできず帰ることになっていたらと思うと……うう。","ENG":"I can't imagine what we would've done if we made it all the way here and got kicked out at the entrance.","TWN":"好不容易來到這裡，如果被拒之門外的話……呃呃。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그래도 다행입니다. 시그마의 지인 중에 티켓을 구할 수 있는 사람이 있어서.","JPN":"シグマのツテでチケットを購入できる方がいたのは、幸いだったね。","ENG":"It is a relief that Sigma's acquaintance could get us tickets.","TWN":"幸運的是西格瑪認識能搞到票的熟人。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말로요. 유미나라는 분한테는 나중에 감사 인사라도 하자고요.","JPN":"はい。ヤナギ・ミナさんには改めてお礼をしましょう。","ENG":"For sure. Let's thank this \\"Yoo Mina\\" person later.","TWN":"嗯嗯。以後一定要好好謝謝這位劉米娜。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유피! 크레데레!","JPN":"ユピ！　クレデレ！","ENG":"Yuppie! Credere!","TWN":"悠菲！克蕾妲莉！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님? 통화는 끝났나요?","JPN":"室長？　お電話はもう済んだのですか？","ENG":"Chief? Are you done with your phone call?","TWN":"室長？通話結束了嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으응. 그것 말인데.","JPN":"あ、うん。その話なんだけど……","ENG":"Yeah. About that.","TWN":"唔，關於那個……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"응? 보물에 대해 뭔가 짚이는 구석은 없냐고?","JPN":"え？　お宝についての私の予想？","ENG":"Hmm? Do I have any guesses about where the treasure is?","TWN":"嗯？我對寶藏有什麼頭緒嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"몰라. 애초에 나는 저번 탐험 이후로 아카데미에만 갇혀 있었다고.","JPN":"見当もつかないわよ。私は前回の探検以来、ずっとアカデミーに引き籠っていたんだから。","ENG":"Not really. I've been stuck in the Academy ever since that last expedition.","TWN":"不清楚。自從上次探險之後，我就一直被留在學院裡。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그것보다… 보물을 찾는 거라면 나를 데리고 가는 건 어때? 분명 다른 녀석들보다-","JPN":"それより、お宝を探しに行くなら私を連れていかない？　きっと他の連中より……","ENG":"If you're looking for treasure, you can always take me! I'm sure I'll be a lot more helpful than–","TWN":"比起這個……如果是找寶藏的話，帶上我怎麼樣？肯定比其他傢伙——"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"히익?!","JPN":"ひいっ……！","ENG":"Eek?!","TWN":"欸？!"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"죄송합니다, 시그마 양. 잠시 소란이 있었군요.","JPN":"申し訳ございません、シグマさん。お騒がせしました。","ENG":"My apologies, Sigma. There was a short disturbance.","TWN":"抱歉，西格瑪，剛剛有點小騷亂。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"복원해 주신 영상을 분석한 결과, 시그마 양의 말 대로 범인이 섬에 있다는 사실은 파악했습니다.","JPN":"復元していただいた映像を解析したところ、シグマさんのおっしゃる通り、犯人はこの島にいることがほぼ確定しました。","ENG":"Based on the analysis of the restored footage, we were able to glean that the criminal is indeed on the island, like you said.","TWN":"根據你恢復的影片進行分析後，我們確認了你所說的犯人確實在島上。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 범인이 전파공작에 능한지… 그 위치까지는 정확히 파악할 수가 없군요.","JPN":"ですが、犯人は電波工作に長けているらしく、位置の把握まではできていません。","ENG":"But this culprit must be skilled in electronic operations... because we could not locate the exact coordinates.","TWN":"但是，犯人同樣擅長反追蹤……我們還無法準確確定其位置。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"모처럼 부탁해 주셨는데 죄송합니다. 별다른 도움은 되지 못할 것 같군요.","JPN":"せっかく要請いただいたのに、あまりお役に立てずすみません。","ENG":"I apologize for not being of more help.","TWN":"難得你開口了，真是抱歉，我恐怕幫不上什麼忙。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아냐, 옌 언니. 티켓을 받은 것만으로도 충분한걸?","JPN":"イェンお姉ちゃん、気にしないで。チケットの件で助けてもらっただけでも十分だよ。","ENG":"Don't say that, Yen. It was more than enough that you got us the tickets.","TWN":"不，嫣杏姊姊。能拿到票就已經足夠了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다른 사람도 아닌 미나 양의 부탁이니까요. 신경 쓰지 않으셔도 된답니다.","JPN":"いえいえ。ミナさんからの頼みとあれば、無下にはできませんので。","ENG":"Anything for Mina. Don't worry about that.","TWN":"又不是別人，是米娜親自開的口。你不用擔心。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스 양에게도 말해 놨으니, 혹여 알게 되는 것이 있다면 곧바로 연락드리죠.","JPN":"イディスさんにもお伝えしておいたので、もしも新しくわかったことがあればすぐにご連絡します。","ENG":"I also talked to Edith, so I will let you know if I hear anything.","TWN":"我已經告訴伊蒂絲了，如果有任何發現，會立刻聯絡你。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물의 위치는 다른 언니들도 잘 모르는 것 같아.","JPN":"お宝の在り処はお姉ちゃんたちも、よく知らないみたい。","ENG":"I don't think the others know the location of the treasure.","TWN":"寶藏的位置好像連其他姊姊們也不太清楚。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};